cardCss:
/*
 * FULL PHOTO
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Full-bleed photo card with legible text overlay
 * Fonts     : Noto Sans JP (wght 100–900 variable) · Noto Serif JP
 * Palette   : Dynamic — derived from the card's picture field
 *
 * Key techniques:
 *   Two-layer background trick: an absolutely-positioned .blur-bg div
 *   fills the card at z-index 0 with the same image, but with
 *   filter: blur(15px) and opacity 0.25 — this creates a soft,
 *   colour-matched ambient blur behind the sharp foreground image,
 *   helping text remain readable against any photo
 *
 *   filter: brightness(0.8) on the foreground image darkens it slightly
 *   so white text has enough contrast without a separate overlay div
 */
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@400&display=swap');

@import url('https://fonts.googleapis.com/css2?family=Noto+Serif+JP:wght@400&display=swap');

:root {

}

.noto-serif-jp {
   font-family: "Noto Serif JP", serif;
}

.noto-sans-jp {
   font-family: "Noto Sans JP", sans-serif;
}

/*.card is primarily for styling the background of both front and back cards*/
.card {
   background-color: black;
}

.ts-4 {
    text-shadow: 0px 0px 4px rgba(0,0,0,.2), 2px 2px 4px rgba(0,0,0,.2), 2px 2px 6px rgba(0,0,0,.2);
}

.image-container {
  position: relative;
  height: 100%;
  overflow: hidden;
  background-color: black;
}

.bg-image {
  position: absolute;
  top: -25%;
  left: -25%;
  height: 150%;
  object-fit: cover;
  filter: blur(15px); /* Apply a blur effect */
  z-index: 0; /* Under the main image */
  opacity: 25%;
}

.bg-image img {
  height: 100%;
  object-fit: cover;
}

.display-image {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  z-index: 1;
  display: flex;
  justify-content: center;
  align-items: center;
}

.display-image img {
  width: 100%;
  height: auto;
  filter: brightness(0.8);
}

.balance {
   text-wrap: balance;
}

.fp-input-wrap input {
  font-family: "Noto Sans JP", sans-serif;
  font-size: 1.1rem;
  background: rgba(0,0,0,0.4);
  border: 1px solid rgba(255,255,255,0.7);
  color: white;
  width: 100%;
  padding: 0.4rem 0.6rem;
  box-sizing: border-box;
  caret-color: white;
  text-align: center;
}
.fp-input-wrap input:focus { outline: none; border-color: white; background: rgba(0,0,0,0.55); }
.fp-input-wrap input::placeholder { color: rgba(255,255,255,0.5); }
.fp-input-wrap input:focus::placeholder { color: transparent; }
